#include <stdio.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        long long A,B,C,X; scanf("%lld %lld %lld %lld", &A, &B, &C, &X);
        if(X==A || X==B || X==C) printf("Yes\n");
        else printf("No\n");
    }
    return 0;
}

